import{_ as e,o as r,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"28. Hours Of Work Full Time Doctors","description":"","frontmatter":{"title":"28. Hours Of Work Full Time Doctors","eba":"Medical Specialists 2022-2026","topics":["hours","employment"]},"headers":[],"relativePath":"ebas/medical-specialists/hours-of-work/28-hours-of-work-full-time-doctors.md","filePath":"ebas/medical-specialists/hours-of-work/28-hours-of-work-full-time-doctors.md"}'),n={name:"ebas/medical-specialists/hours-of-work/28-hours-of-work-full-time-doctors.md"};function a(i,o,l,h,c,p){return r(),t("div",null,[...o[0]||(o[0]=[s('<h1 id="_28-hours-of-work-full-time-doctors" tabindex="-1">28. Hours Of Work Full Time Doctors <a class="header-anchor" href="#_28-hours-of-work-full-time-doctors" aria-label="Permalink to &quot;28. Hours Of Work Full Time Doctors&quot;">​</a></h1><p><strong>28.1</strong> The ordinary hours of work for a Full-time Doctor will be an average of 38 hours per week and may be worked by agreement between the Health Service and the Full-time Doctor in one of the following ways:</p><p><strong>(a)</strong> over five days per week;</p><p><strong>(b)</strong> over four days per week;</p><p><strong>(c)</strong> over 19 days per four week period; or</p><p><strong>(d)</strong> over 40 hours in any period of seven consecutive days or 80 hours in any period of 14 consecutive days.</p><p><strong>28.2</strong> A Health Service may require a Doctor to work reasonable additional hours. In determining whether additional hours are reasonable, the following must be taken into account:</p><p><strong>(a)</strong> any risk to Doctor health and safety from working the additional hours;</p><p><strong>(b)</strong> the Doctor&#39;s personal circumstances, including family responsibilities;</p><p><strong>(c)</strong> the needs of the workplace or enterprise in which the Doctor is employed;</p><p><strong>(d)</strong> whether the Doctor is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, working additional hours;</p><p><strong>(e)</strong> any notice given by the Health Service of any request or requirement to work the additional hours;</p><p><strong>(f)</strong> any notice given by the Doctor of his or her intention to refuse to work the additional hours;</p><p><strong>(g)</strong> the usual patterns of work in the industry, or the part of an industry, in which the Doctor works;</p><p><strong>(h)</strong> the nature of the Doctor&#39;s role, and the Doctor&#39;s level of responsibility;</p><p><strong>(i)</strong> whether the additional hours are in accordance with averaging terms included in the Agreement;</p><p><strong>(j)</strong> any other relevant matter.</p><p><strong>28.3</strong> Where a Doctor has sought an amendment to the agreed Hours of Work arrangements as prescribed in subclause 28.1 and has done so in writing, the Doctor must be provided with a response in writing.</p><p>Plain language terms: ordinary hours.</p>',19)])])}const g=e(n,[["render",a]]);export{u as __pageData,g as default};
